// ─── RESPONSIVE SYSTEM ───
const BP = { sm: 0, md: 640, lg: 768, xl: 1024, xl2: 1440 };
const useBreakpoint = () => {
  const [bp, setBp] = useState(() => {
    if (typeof window === "undefined") return "xl";
    const w = window.innerWidth;
    if (w < BP.md) return "sm";
    if (w < BP.lg) return "md";
    if (w < BP.xl) return "lg";
    if (w < BP.xl2) return "xl";
    return "xl2";
  });
  useEffect(() => {
    const onResize = () => {
      const w = window.innerWidth;
      const next = w < BP.md ? "sm" : w < BP.lg ? "md" : w < BP.xl ? "lg" : w < BP.xl2 ? "xl" : "xl2";
      setBp(prev => prev !== next ? next : prev);
    };
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);
  return bp;
};
// Responsive value: rv(bp, { sm, md?, lg?, xl?, xl2? }) — falls back to smaller
const rv = (bp, vals) => {
  const order = ["sm", "md", "lg", "xl", "xl2"];
  const idx = order.indexOf(bp);
  for (let i = idx; i >= 0; i--) { if (vals[order[i]] !== undefined) return vals[order[i]]; }
  return vals.sm;
};
// Responsive grid columns shorthand
const rg = (bp, vals) => `repeat(${rv(bp, vals)}, 1fr)`;
// Breakpoint booleans
const isMobile = (bp) => bp === "sm";
const isTablet = (bp) => bp === "md" || bp === "lg";
const isSmall = (bp) => bp === "sm" || bp === "md";
const isCompact = (bp) => bp === "sm" || bp === "md" || bp === "lg";

