// ─── THEME PICKER ───
const ThemePicker = ({ currentTheme, setTheme, collapsed }) => {
  const [open, setOpen] = useState(false);
  const themes = Object.values(THEMES);
  const current = THEMES[currentTheme];

  return (
    <div style={{ position: "relative" }}>
      <div onClick={() => setOpen(!open)}
        style={{ display: "flex", alignItems: "center", justifyContent: collapsed ? "center" : "flex-start", gap: 8, padding: collapsed ? "10px 8px" : "8px 12px", borderRadius: 8, cursor: "pointer", color: COLORS.textMuted, fontSize: 12, transition: "all 0.2s", fontWeight: 500, background: open ? COLORS.surfaceAlt : "transparent" }}
        onMouseEnter={e => e.currentTarget.style.background = COLORS.surfaceAlt}
        onMouseLeave={e => { if (!open) e.currentTarget.style.background = "transparent"; }}
        title={collapsed ? `Theme: ${current.name}` : undefined}
      >
        {collapsed ? (
          /* Collapsed: stacked color circles */
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 3 }}>
            {current.preview.map((c, i) => (
              <div key={i} style={{ width: 10, height: 10, borderRadius: "50%", background: c, border: `1.5px solid ${COLORS.borderLight}`, boxShadow: `0 0 0 1px ${c}40` }} />
            ))}
          </div>
        ) : (
          /* Expanded: horizontal bars + label */
          <>
            <div style={{ display: "flex", gap: 2, flexShrink: 0 }}>
              {current.preview.map((c, i) => (
                <div key={i} style={{ width: 6, height: 14, borderRadius: 2, background: c, border: "1px solid rgba(255,255,255,0.1)" }} />
              ))}
            </div>
            <span>{current.name}</span>
            <Palette size={13} style={{ marginLeft: "auto", opacity: 0.5 }} />
          </>
        )}
      </div>

      {open && (
        <>
          <div onClick={() => setOpen(false)} style={{ position: "fixed", inset: 0, zIndex: 999 }} />
          <div style={{ position: "absolute", bottom: collapsed ? 0 : "100%", left: collapsed ? "100%" : 0, marginBottom: collapsed ? 0 : 6, marginLeft: collapsed ? 6 : 0, width: 260, background: COLORS.surface, border: `1px solid ${COLORS.border}`, borderRadius: 14, boxShadow: "0 12px 40px rgba(0,0,0,0.4)", zIndex: 1000, overflow: "hidden", animation: "modalIn 0.2s ease" }}>
            <div style={{ padding: "14px 16px 10px", borderBottom: `1px solid ${COLORS.border}` }}>
              <div style={{ fontSize: 13, fontWeight: 700, color: COLORS.text }}>Appearance</div>
              <div style={{ fontSize: 11, color: COLORS.textDim, marginTop: 2 }}>Choose your preferred theme</div>
            </div>
            <div style={{ padding: "8px 8px 10px", display: "flex", flexDirection: "column", gap: 2 }}>
              {themes.map(t => {
                const active = currentTheme === t.id;
                return (
                  <div key={t.id}
                    onClick={() => { setTheme(t.id); setOpen(false); }}
                    style={{ display: "flex", alignItems: "center", gap: 10, padding: "10px 12px", borderRadius: 10, cursor: "pointer", background: active ? COLORS.primaryBg : "transparent", border: active ? `1px solid ${COLORS.primary}40` : "1px solid transparent", transition: "all 0.15s" }}
                    onMouseEnter={e => { if (!active) e.currentTarget.style.background = COLORS.surfaceAlt; }}
                    onMouseLeave={e => { if (!active) e.currentTarget.style.background = "transparent"; }}
                  >
                    {/* Preview swatches */}
                    <div style={{ display: "flex", gap: 3, padding: 4, background: t.bg, borderRadius: 6, border: `1px solid ${t.border}` }}>
                      {t.preview.map((c, i) => (
                        <div key={i} style={{ width: 10, height: 10, borderRadius: "50%", background: c, boxShadow: `0 0 0 1px ${c}40` }} />
                      ))}
                    </div>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontSize: 12, fontWeight: active ? 600 : 500, color: active ? COLORS.primaryLight : COLORS.text }}>{t.name}</div>
                      <div style={{ fontSize: 10, color: COLORS.textDim }}>{t.isDark ? "Dark" : "Light"}</div>
                    </div>
                    {active && <Check size={14} style={{ color: COLORS.primary }} />}
                  </div>
                );
              })}
            </div>
          </div>
        </>
      )}
    </div>
  );
};

// ─── DATE FORMATTER ───
const formatDate = (dateStr) => {
  if (!dateStr) return "";
  const months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
  const d = new Date(dateStr + "T00:00:00");
  if (isNaN(d)) return dateStr;
  return `${String(d.getDate()).padStart(2, "0")} ${months[d.getMonth()]} ${d.getFullYear()}`;
};

// ─── Utility Components ───
const Badge = ({ children, color = "primary", size = "sm" }) => {
  const colorMap = {
    primary: { bg: COLORS.primaryBg, text: COLORS.primaryLight, border: COLORS.primaryLight + "30" },
    success: { bg: COLORS.successBg, text: COLORS.success, border: COLORS.success + "30" },
    warning: { bg: COLORS.warningBg, text: COLORS.warning, border: COLORS.warning + "30" },
    danger: { bg: COLORS.dangerBg, text: COLORS.danger, border: COLORS.danger + "30" },
    accent: { bg: COLORS.accentBg, text: COLORS.accent, border: COLORS.accent + "30" },
    orange: { bg: COLORS.orangeBg, text: COLORS.orange, border: COLORS.orange + "30" },
    neutral: { bg: COLORS.surfaceAlt, text: COLORS.textMuted, border: COLORS.border },
  };
  const c = colorMap[color];
  return (
    <span style={{ display: "inline-flex", alignItems: "center", gap: 4, padding: size === "sm" ? "2px 8px" : "4px 12px", borderRadius: 6, background: c.bg, color: c.text, fontSize: size === "sm" ? 11 : 12, fontWeight: 600, border: `1px solid ${c.border}`, letterSpacing: 0.3 }}>
      {children}
    </span>
  );
};

const StatusBadge = ({ status }) => {
  const map = { in_stock: ["In Stock", "success"], low_stock: ["Low Stock", "warning"], out_of_stock: ["Out of Stock", "danger"], active: ["Active", "success"], inactive: ["Inactive", "neutral"], pending: ["Pending", "orange"], approved: ["Approved", "success"], rejected: ["Rejected", "danger"], in_transit: ["In Transit", "accent"], completed: ["Completed", "success"], draft: ["Draft", "neutral"], shipped: ["Shipped", "accent"], partial: ["Partial", "warning"], received: ["Received", "success"], cancelled: ["Cancelled", "danger"] };
  const [label, color] = map[status] || [status, "neutral"];
  return <Badge color={color}>{label}</Badge>;
};

const Card = ({ children, style, onClick, hover }) => (
  <div
    onClick={onClick}
    style={{ background: COLORS.surface, borderRadius: 14, border: `1px solid ${COLORS.border}`, padding: 20, cursor: onClick ? "pointer" : "default", transition: "all 0.2s", overflowX: "auto", ...style }}
    onMouseEnter={e => { if (hover || onClick) { e.currentTarget.style.borderColor = COLORS.primaryLight; e.currentTarget.style.transform = "translateY(-1px)"; } }}
    onMouseLeave={e => { if (hover || onClick) { e.currentTarget.style.borderColor = COLORS.border; e.currentTarget.style.transform = "translateY(0)"; } }}
  >
    {children}
  </div>
);

const Button = ({ children, variant = "primary", size = "md", icon: Icon, onClick, style: s, disabled }) => {
  const base = { display: "inline-flex", alignItems: "center", gap: 6, borderRadius: 10, fontWeight: 600, cursor: disabled ? "not-allowed" : "pointer", border: "none", transition: "all 0.2s", fontSize: size === "sm" ? 12 : 13, padding: size === "sm" ? "6px 12px" : "10px 18px", opacity: disabled ? 0.5 : 1, fontFamily: "inherit" };
  const variants = {
    primary: { background: `linear-gradient(135deg, ${COLORS.primary}, ${COLORS.primaryDark})`, color: "#fff", boxShadow: `0 2px 12px ${COLORS.primary}50` },
    secondary: { background: COLORS.surfaceAlt, color: COLORS.text, border: `1px solid ${COLORS.border}` },
    ghost: { background: "transparent", color: COLORS.textMuted, padding: size === "sm" ? "6px 8px" : "10px 12px" },
    danger: { background: COLORS.dangerBg, color: COLORS.danger, border: `1px solid ${COLORS.danger}30` },
    success: { background: COLORS.successBg, color: COLORS.success, border: `1px solid ${COLORS.success}30` },
    accent: { background: COLORS.accentBg, color: COLORS.accent, border: `1px solid ${COLORS.accent}30`, boxShadow: `0 2px 12px ${COLORS.accent}25` },
  };
  return (
    <button onClick={onClick} disabled={disabled} style={{ ...base, ...variants[variant], ...s }}
      onMouseEnter={e => { if (!disabled) e.currentTarget.style.transform = "translateY(-1px)"; }}
      onMouseLeave={e => { if (!disabled) e.currentTarget.style.transform = "translateY(0)"; }}
    >
      {Icon && <Icon size={size === "sm" ? 14 : 16} />}{children}
    </button>
  );
};

const Input = ({ icon: Icon, style: s, ...props }) => (
  <div style={{ position: "relative", ...s }}>
    {Icon && <Icon size={16} style={{ position: "absolute", left: 12, top: "50%", transform: "translateY(-50%)", color: COLORS.textDim }} />}
    <input {...props} style={{ width: "100%", padding: Icon ? "10px 12px 10px 38px" : "10px 12px", background: COLORS.surfaceAlt, border: `1px solid ${COLORS.border}`, borderRadius: 10, color: COLORS.text, fontSize: 13, outline: "none", fontFamily: "inherit", boxSizing: "border-box", transition: "border-color 0.2s", ...(props.style || {}) }}
      onFocus={e => e.target.style.borderColor = COLORS.primary}
      onBlur={e => e.target.style.borderColor = COLORS.border}
    />
  </div>
);

const Select = ({ options, style: s, ...props }) => (
  <select {...props} style={{ width: "100%", padding: "10px 12px", background: COLORS.surfaceAlt, border: `1px solid ${COLORS.border}`, borderRadius: 10, color: COLORS.text, fontSize: 13, outline: "none", fontFamily: "inherit", cursor: "pointer", appearance: "none", ...(s || {}) }}>{options.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}</select>
);

// ─── Reusable Pagination ───
const paginate = (arr, page, perPage) => {
  const total = arr.length;
  const totalPages = Math.max(1, Math.ceil(total / perPage));
  const safePage = Math.min(Math.max(1, page), totalPages);
  const start = (safePage - 1) * perPage;
  return { items: arr.slice(start, start + perPage), page: safePage, totalPages, total, start };
};

const Paginator = ({ total, page, totalPages, perPage, onPage, start, colors }) => {
  if (total <= perPage) return null;
  const c = colors || { text: COLORS.text, textDim: COLORS.textDim, textMuted: COLORS.textMuted, primary: COLORS.primary, border: COLORS.border, surface: COLORS.surface, surfaceAlt: COLORS.surfaceAlt };
  const end = Math.min(start + perPage, total);
  // Compute visible page numbers: show max 5 pages centered on current
  const maxVis = 5;
  let pStart = Math.max(1, page - Math.floor(maxVis / 2));
  let pEnd = Math.min(totalPages, pStart + maxVis - 1);
  if (pEnd - pStart + 1 < maxVis) pStart = Math.max(1, pEnd - maxVis + 1);
  const pageNums = [];
  for (let i = pStart; i <= pEnd; i++) pageNums.push(i);

  return (
    <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", flexWrap: "wrap", gap: 8, padding: "10px 0", marginTop: 6 }}>
      <span style={{ fontSize: 11, color: c.textDim }}>Showing {start + 1}–{end} of {total}</span>
      <div style={{ display: "flex", alignItems: "center", gap: 2 }}>
        <button onClick={() => onPage(1)} disabled={page <= 1}
          style={{ width: 28, height: 28, borderRadius: 6, border: `1px solid ${c.border}`, background: "transparent", color: page <= 1 ? c.textDim : c.textMuted, fontSize: 10, cursor: page <= 1 ? "default" : "pointer", fontFamily: "inherit", opacity: page <= 1 ? 0.4 : 1, display: "flex", alignItems: "center", justifyContent: "center" }}>«</button>
        <button onClick={() => onPage(Math.max(1, page - 1))} disabled={page <= 1}
          style={{ width: 28, height: 28, borderRadius: 6, border: `1px solid ${c.border}`, background: "transparent", color: page <= 1 ? c.textDim : c.textMuted, fontSize: 10, cursor: page <= 1 ? "default" : "pointer", fontFamily: "inherit", opacity: page <= 1 ? 0.4 : 1, display: "flex", alignItems: "center", justifyContent: "center" }}>‹</button>
        {pStart > 1 && <span style={{ fontSize: 10, color: c.textDim, padding: "0 2px" }}>…</span>}
        {pageNums.map(n => (
          <button key={n} onClick={() => onPage(n)}
            style={{ width: 28, height: 28, borderRadius: 6, border: n === page ? `1.5px solid ${c.primary}` : `1px solid ${c.border}`, background: n === page ? `${c.primary}20` : "transparent", color: n === page ? c.primary : c.textMuted, fontSize: 11, fontWeight: n === page ? 700 : 500, cursor: "pointer", fontFamily: "inherit" }}>{n}</button>
        ))}
        {pEnd < totalPages && <span style={{ fontSize: 10, color: c.textDim, padding: "0 2px" }}>…</span>}
        <button onClick={() => onPage(Math.min(totalPages, page + 1))} disabled={page >= totalPages}
          style={{ width: 28, height: 28, borderRadius: 6, border: `1px solid ${c.border}`, background: "transparent", color: page >= totalPages ? c.textDim : c.textMuted, fontSize: 10, cursor: page >= totalPages ? "default" : "pointer", fontFamily: "inherit", opacity: page >= totalPages ? 0.4 : 1, display: "flex", alignItems: "center", justifyContent: "center" }}>›</button>
        <button onClick={() => onPage(totalPages)} disabled={page >= totalPages}
          style={{ width: 28, height: 28, borderRadius: 6, border: `1px solid ${c.border}`, background: "transparent", color: page >= totalPages ? c.textDim : c.textMuted, fontSize: 10, cursor: page >= totalPages ? "default" : "pointer", fontFamily: "inherit", opacity: page >= totalPages ? 0.4 : 1, display: "flex", alignItems: "center", justifyContent: "center" }}>»</button>
      </div>
    </div>
  );
};

const MiniChart = ({ data, color, height = 40 }) => {
  const max = Math.max(...data);
  const min = Math.min(...data);
  const range = max - min || 1;
  const w = 120;
  const points = data.map((v, i) => `${(i / (data.length - 1)) * w},${height - ((v - min) / range) * (height - 4) - 2}`).join(" ");
  return (
    <svg width={w} height={height} style={{ display: "block" }}>
      <defs>
        <linearGradient id={`grad-${color}`} x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor={color} stopOpacity="0.3" />
          <stop offset="100%" stopColor={color} stopOpacity="0" />
        </linearGradient>
      </defs>
      <polygon points={`0,${height} ${points} ${w},${height}`} fill={`url(#grad-${color})`} />
      <polyline points={points} fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
};

// Progress bar
const ProgressBar = ({ value, max, color = COLORS.primary }) => (
  <div style={{ width: "100%", height: 6, background: COLORS.surfaceAlt, borderRadius: 3, overflow: "hidden" }}>
    <div style={{ width: `${Math.min((value / max) * 100, 100)}%`, height: "100%", background: color, borderRadius: 3, transition: "width 0.5s ease" }} />
  </div>
);

