  general_manager:   { dash_view: "full", dash_export: "full", prod_view: "full", prod_edit: "full", prod_delete: "full", prod_price: "full", cat_view: "full", cat_edit: "full", uom_view: "full", uom_edit: "full", pos_sales: "full", pos_discount: "full", pos_void: "full", pos_receipts: "full", po_view: "full", po_create: "full", po_approve: "full", sup_view: "full", sup_edit: "full", wh_view: "full", wh_manage: "full", adj_view: "full", adj_create: "full", adj_approve: "full", xfer_view: "full", xfer_create: "full", team_view: "full", team_invite: "full", team_roles: "full", set_shop: "full", set_billing: "none", set_delete: "none" },
