// ─── Register Screen ───
const RegisterScreen = ({ setAuthScreen, bp }) => {
  const [form, setForm] = useState({ firstName: "", lastName: "", email: "", phone: "", password: "", confirmPassword: "" });
  const [showPass, setShowPass] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [agreedTerms, setAgreedTerms] = useState(false);
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState({});

  const u = (field, val) => { setForm(prev => ({ ...prev, [field]: val })); setErrors(prev => ({ ...prev, [field]: "" })); };

  const validate = () => {
    const e = {};
    if (!form.firstName.trim()) e.firstName = "First name is required";
    if (!form.lastName.trim()) e.lastName = "Last name is required";
    if (!form.email.trim()) e.email = "Email is required";
    else if (!/\S+@\S+\.\S+/.test(form.email)) e.email = "Enter a valid email";
    if (!form.phone.trim()) e.phone = "Phone number is required";
    if (!form.password) e.password = "Password is required";
    else if (form.password.length < 8) e.password = "Password must be 8+ characters";
    if (form.password !== form.confirmPassword) e.confirmPassword = "Passwords do not match";
    if (!agreedTerms) e.terms = "You must agree to the terms";
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleRegister = () => {
    if (!validate()) return;
    setLoading(true);
    setTimeout(() => { setLoading(false); setAuthScreen("verify"); }, 1500);
  };

  return (
    <div>
      <AuthBranding bp={bp} />
      <div style={{ marginBottom: 24 }}>
        <h1 style={{ fontSize: rv(bp, { sm: 22, md: 26 }), fontWeight: 800, color: COLORS.text, margin: 0 }}>Create your account</h1>
        <p style={{ fontSize: 14, color: COLORS.textDim, margin: "6px 0 0" }}>Start managing your business in minutes</p>
      </div>

      <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
        <div style={{ display: "grid", gridTemplateColumns: rv(bp, { sm: "1fr 1fr" }), gap: 10 }}>
          <AuthInput icon={User} label="First Name" placeholder="Kofi" value={form.firstName} onChange={e => u("firstName", e.target.value)} error={errors.firstName} />
          <AuthInput label="Last Name" placeholder="Mensah" value={form.lastName} onChange={e => u("lastName", e.target.value)} error={errors.lastName} />
        </div>
        <AuthInput icon={Mail} label="Email Address" type="email" placeholder="kofi@example.com" value={form.email} onChange={e => u("email", e.target.value)} error={errors.email} />
        <AuthInput icon={Phone} label="Phone Number" type="tel" placeholder="+233 24 000 0000" value={form.phone} onChange={e => u("phone", e.target.value)} error={errors.phone} />
        <AuthInput icon={Lock} label="Password" type={showPass ? "text" : "password"} placeholder="Create a strong password" value={form.password} onChange={e => u("password", e.target.value)} error={errors.password}
          rightIcon={showPass ? <EyeOff size={16} style={{ color: COLORS.textDim }} /> : <Eye size={16} style={{ color: COLORS.textDim }} />}
          onRightIconClick={() => setShowPass(!showPass)}
        />
        <PasswordStrength password={form.password} />
        <AuthInput icon={Lock} label="Confirm Password" type={showConfirm ? "text" : "password"} placeholder="Re-enter your password" value={form.confirmPassword} onChange={e => u("confirmPassword", e.target.value)} error={errors.confirmPassword}
          rightIcon={showConfirm ? <EyeOff size={16} style={{ color: COLORS.textDim }} /> : <Eye size={16} style={{ color: COLORS.textDim }} />}
          onRightIconClick={() => setShowConfirm(!showConfirm)}
        />

        {/* Terms */}
        <div style={{ marginTop: 4 }}>
          <div onClick={() => { setAgreedTerms(!agreedTerms); setErrors(prev => ({ ...prev, terms: "" })); }} style={{ display: "flex", alignItems: "flex-start", gap: 10, cursor: "pointer" }}>
            <div style={{
              width: 18, height: 18, borderRadius: 5, border: `1.5px solid ${errors.terms ? COLORS.danger : agreedTerms ? COLORS.primary : COLORS.border}`,
              background: agreedTerms ? COLORS.primary : "transparent", display: "flex", alignItems: "center", justifyContent: "center", transition: "all 0.2s", flexShrink: 0, marginTop: 1,
            }}>
              {agreedTerms && <Check size={12} style={{ color: "#fff" }} />}
            </div>
            <span style={{ fontSize: 13, color: COLORS.textMuted, lineHeight: 1.4 }}>
              I agree to the <span style={{ fontWeight: 600, color: COLORS.primary }}>Terms of Service</span> and <span style={{ fontWeight: 600, color: COLORS.primary }}>Privacy Policy</span>
            </span>
          </div>
          {errors.terms && <div style={{ fontSize: 11, color: COLORS.danger, marginTop: 4, marginLeft: 28 }}><AlertTriangle size={11} /> {errors.terms}</div>}
        </div>

        <AuthButton onClick={handleRegister} loading={loading} style={{ marginTop: 4 }}>
          <ArrowRight size={16} /> Create Account
        </AuthButton>
      </div>

      <div style={{ textAlign: "center", fontSize: 14, color: COLORS.textMuted, marginTop: 20 }}>
        Already have an account?{" "}
        <span onClick={() => setAuthScreen("login")} style={{ fontWeight: 700, color: COLORS.primary, cursor: "pointer" }}>Sign in</span>
      </div>
    </div>
  );
};

// ─── Email Verification Screen ───
const VerifyScreen = ({ setAuthScreen, onVerified, bp }) => {
  const [otp, setOtp] = useState("");
  const [loading, setLoading] = useState(false);
  const [resendTimer, setResendTimer] = useState(60);
  const [verified, setVerified] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    if (resendTimer > 0) {
      const t = setTimeout(() => setResendTimer(resendTimer - 1), 1000);
      return () => clearTimeout(t);
    }
  }, [resendTimer]);

  const handleVerify = () => {
    if (otp.length < 6) { setError("Please enter the full 6-digit code"); return; }
    setLoading(true);
    setError("");
    setTimeout(() => {
      setLoading(false);
      setVerified(true);
      setTimeout(() => onVerified(), 2000);
    }, 1200);
  };

  const handleResend = () => {
    if (resendTimer > 0) return;
    setResendTimer(60);
    setOtp("");
    setError("");
  };

  if (verified) {
    return (
      <div style={{ textAlign: "center", padding: "40px 0" }}>
        <div style={{
          width: 80, height: 80, borderRadius: "50%", background: COLORS.successBg, display: "inline-flex",
          alignItems: "center", justifyContent: "center", marginBottom: 20,
          border: `2px solid ${COLORS.success}40`, animation: "modalIn 0.5s ease",
        }}>
          <CheckCircle size={36} style={{ color: COLORS.success }} />
        </div>
        <h2 style={{ fontSize: 22, fontWeight: 800, color: COLORS.text, margin: "0 0 8px" }}>Email Verified!</h2>
        <p style={{ fontSize: 14, color: COLORS.textDim, margin: 0 }}>Redirecting you to set up your shop...</p>
        <div style={{ marginTop: 20 }}>
          <div style={{ width: 18, height: 18, border: `2.5px solid ${COLORS.border}`, borderTopColor: COLORS.primary, borderRadius: "50%", animation: "spin 0.8s linear infinite", margin: "0 auto" }} />
        </div>
      </div>
    );
  }

  return (
    <div>
      <AuthBranding bp={bp} />
      <div style={{ textAlign: "center", marginBottom: 28 }}>
        <div style={{
          width: 60, height: 60, borderRadius: 16, background: COLORS.primaryBg, display: "inline-flex",
          alignItems: "center", justifyContent: "center", marginBottom: 16,
        }}>
          <Mail size={28} style={{ color: COLORS.primary }} />
        </div>
        <h1 style={{ fontSize: rv(bp, { sm: 22, md: 26 }), fontWeight: 800, color: COLORS.text, margin: "0 0 8px" }}>Check your email</h1>
        <p style={{ fontSize: 14, color: COLORS.textDim, margin: 0, lineHeight: 1.5 }}>
          We sent a verification code to<br />
          <span style={{ fontWeight: 700, color: COLORS.text }}>k•••@example.com</span>
        </p>
      </div>

      {error && (
        <div style={{ padding: "10px 14px", borderRadius: 10, background: "rgba(239,68,68,0.1)", border: `1px solid ${COLORS.danger}25`, marginBottom: 16, textAlign: "center", fontSize: 13, color: COLORS.danger, fontWeight: 500 }}>
          {error}
        </div>
      )}

      <div style={{ marginBottom: 24 }}>
        <OtpInput length={6} value={otp} onChange={(v) => { setOtp(v); setError(""); }} />
      </div>

      <AuthButton onClick={handleVerify} loading={loading} disabled={otp.length < 6}>
        <CheckCircle size={16} /> Verify Email
      </AuthButton>

      <div style={{ textAlign: "center", marginTop: 20 }}>
        {resendTimer > 0 ? (
          <span style={{ fontSize: 13, color: COLORS.textDim }}>
            Resend code in <span style={{ fontWeight: 700, color: COLORS.text, fontFamily: "monospace" }}>{resendTimer}s</span>
          </span>
        ) : (
          <span onClick={handleResend} style={{ fontSize: 13, fontWeight: 600, color: COLORS.primary, cursor: "pointer", display: "inline-flex", alignItems: "center", gap: 4 }}>
            <RefreshCw size={13} /> Resend code
          </span>
        )}
      </div>

      <div style={{ textAlign: "center", marginTop: 12 }}>
        <span onClick={() => setAuthScreen("register")} style={{ fontSize: 13, color: COLORS.textDim, cursor: "pointer" }}>
          <ArrowLeft size={12} style={{ verticalAlign: "middle", marginRight: 4 }} />Change email address
        </span>
      </div>
    </div>
  );
};

