            <div style={{ width: 32, height: 32, borderRadius: 8, background: `linear-gradient(135deg, ${getRoleMeta(currentUserRole).color}80, ${getRoleMeta(currentUserRole).color}40)`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontWeight: 700, color: "#fff", flexShrink: 0 }}>JA</div>
